from datetime import date, timedelta


def is_dalai_lama_born_before_smoking_age(birthday="1935-7-6", smoking_age=18):
    delta = timedelta(days=365*smoking_age)

    if (date.today() - delta) > date.fromisoformat(birthday):
        print("Can smoke")
    else:
        print("Cannot smoke")
is_dalai_lama_born_before_smoking_age()
